import React, { useState } from 'react';
import { db, storage } from '../firebase'; // 🚨 Added storage import
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage'; // 🚨 Firebase upload tools
import { ArrowLeft, Send, UploadCloud, Link as LinkIcon, Type, AlignLeft, LayoutGrid } from 'lucide-react';

function AddProject({ user, onBack }) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [imageFile, setImageFile] = useState(null); // 🚨 State to hold the physical file
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: 'Web App',
    liveDemoUrl: ''
  });

  const categories = ['Web App', 'Mobile App', 'Game', 'AI / ML', 'IoT / Hardware'];

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    
    try {
      let finalImageUrl = '';

      // 1️⃣ If the user selected an image, upload it to Firebase Storage FIRST
      if (imageFile) {
        // Create a unique name so images don't overwrite each other
        const imageRef = ref(storage, `project_covers/${Date.now()}_${imageFile.name}`);
        await uploadBytes(imageRef, imageFile);
        finalImageUrl = await getDownloadURL(imageRef); // Get the secure link
      }

      // 2️⃣ Save the project to the Firestore Database
      await addDoc(collection(db, "projects"), {
        title: formData.title,
        description: formData.description,
        category: formData.category,
        imageUrl: finalImageUrl, // Use the uploaded URL here
        liveDemoUrl: formData.liveDemoUrl,
        authorName: user?.name || 'Student',
        authorUsername: user?.username || 'unknown',
        status: 'Pending', 
        views: 0,
        createdAt: serverTimestamp()
      });
      
      alert("Project submitted successfully! It is now pending Admin approval.");
      onBack(); 
    } catch (error) {
      console.error("Error adding document: ", error);
      alert("Failed to submit project. Make sure your Firebase Storage rules allow uploads!");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white font-sans py-12 px-6 selection:bg-indigo-500/30">
      <div className="max-w-3xl mx-auto">
        
        <button onClick={onBack} className="flex items-center gap-2 text-gray-400 hover:text-white mb-8 transition-colors font-medium">
          <ArrowLeft className="w-5 h-5" /> Back to Gallery
        </button>

        <div className="bg-white/5 backdrop-blur-xl border border-white/10 rounded-[2.5rem] p-8 sm:p-12 shadow-2xl relative overflow-hidden">
          <div className="absolute top-0 right-0 w-96 h-96 bg-indigo-600/10 blur-[100px] rounded-full pointer-events-none"></div>

          <div className="relative z-10 mb-10">
            <h1 className="text-3xl font-extrabold text-white mb-2">Submit Your Project</h1>
            <p className="text-gray-400">Upload your innovation to the repository.</p>
          </div>

          <form onSubmit={handleSubmit} className="relative z-10 space-y-6">
            
            <div>
              <label className="block text-sm font-bold text-gray-300 mb-2 uppercase tracking-wide">Project Title</label>
              <div className="relative">
                <Type className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                <input 
                  type="text" required value={formData.title}
                  onChange={(e) => setFormData({...formData, title: e.target.value})}
                  className="w-full bg-black/50 border border-white/10 rounded-2xl pl-12 pr-4 py-4 outline-none focus:border-indigo-500 transition-all text-white placeholder-gray-600"
                  placeholder="e.g. NextGen AI Assistant"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-300 mb-2 uppercase tracking-wide">Category</label>
              <div className="relative">
                <LayoutGrid className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                <select 
                  value={formData.category} onChange={(e) => setFormData({...formData, category: e.target.value})}
                  className="w-full bg-black/50 border border-white/10 rounded-2xl pl-12 pr-4 py-4 outline-none focus:border-indigo-500 transition-all text-white appearance-none cursor-pointer"
                >
                  {categories.map(cat => <option key={cat} value={cat} className="bg-[#0a0a0a]">{cat}</option>)}
                </select>
              </div>
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-300 mb-2 uppercase tracking-wide">Description</label>
              <div className="relative">
                <AlignLeft className="absolute left-4 top-4 w-5 h-5 text-gray-500" />
                <textarea 
                  required rows="4" value={formData.description}
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  className="w-full bg-black/50 border border-white/10 rounded-2xl pl-12 pr-4 py-4 outline-none focus:border-indigo-500 transition-all text-white placeholder-gray-600 resize-none"
                  placeholder="What problem does your project solve?"
                ></textarea>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* 🚨 THE NEW FILE UPLOAD INPUT */}
              <div>
                <label className="block text-sm font-bold text-gray-300 mb-2 uppercase tracking-wide">Upload Cover Image</label>
                <div className="relative overflow-hidden">
                  <UploadCloud className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                  <input 
                    type="file" 
                    accept="image/*"
                    onChange={(e) => setImageFile(e.target.files[0])}
                    className="w-full bg-black/50 border border-white/10 rounded-2xl pl-12 pr-4 py-3.5 outline-none focus:border-indigo-500 transition-all text-gray-400 file:mr-4 file:py-2 file:px-4 file:rounded-xl file:border-0 file:text-sm file:font-bold file:bg-indigo-600 file:text-white hover:file:bg-indigo-500 cursor-pointer"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-bold text-gray-300 mb-2 uppercase tracking-wide">Live Demo / Repo URL</label>
                <div className="relative">
                  <LinkIcon className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-500" />
                  <input 
                    type="url" value={formData.liveDemoUrl}
                    onChange={(e) => setFormData({...formData, liveDemoUrl: e.target.value})}
                    className="w-full bg-black/50 border border-white/10 rounded-2xl pl-12 pr-4 py-4 outline-none focus:border-indigo-500 transition-all text-white placeholder-gray-600"
                    placeholder="https://github.com/..."
                  />
                </div>
              </div>
            </div>

            <button 
              type="submit" disabled={isSubmitting}
              className={`w-full mt-6 py-4 rounded-2xl font-bold text-lg flex justify-center items-center gap-2 transition-all shadow-xl ${
                isSubmitting ? 'bg-gray-700 text-gray-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-500 text-white hover:shadow-indigo-500/20 active:scale-[0.98]'
              }`}
            >
              {isSubmitting ? 'Uploading securely...' : <>Submit for Approval <Send className="w-5 h-5" /></>}
            </button>

          </form>
        </div>
      </div>
    </div>
  );
}

export default AddProject;
